import pytest

AC_UID = "7c792480bc275ff9"
AC_TYPE = "data"


def test_AC4():
    """
    GIVEN: agents/changelog-analyst.md Phase 2 dev-report enrichment section
    WHEN:  a reader reads the dev-report enrichment procedure
    THEN:  the text specifies that paths in dev.files_modified/dev.files_created absent from the baseline diff AND not in baseline_dirty_snapshot are classified as 'provenance_anomaly' and excluded from commit-message type/scope/summary derivation
    """
    import pathlib
    repo_root = pathlib.Path(__file__).parents[3]
    text = (repo_root / "agents" / "changelog-analyst.md").read_text()

    assert "provenance_anomaly" in text, \
        "provenance_anomaly not found in agents/changelog-analyst.md"
    assert "baseline_head_sha" in text, \
        "baseline_head_sha not found in agents/changelog-analyst.md"

    # Both must appear in Phase 2 section
    phase2_idx = text.find("### Phase 2")
    assert phase2_idx >= 0, "Phase 2 section not found in agents/changelog-analyst.md"
    phase2_text = text[phase2_idx:]

    assert "provenance_anomaly" in phase2_text, \
        "provenance_anomaly not found in Phase 2 section of agents/changelog-analyst.md"
    assert "baseline_head_sha" in phase2_text, \
        "baseline_head_sha not found in Phase 2 section of agents/changelog-analyst.md"

    # Verify the diff form is correct: working-tree (not ..HEAD) at Phase 2 time (pre-commit)
    # The ..HEAD form would be empty before commit and wrongly classify all changes as anomalies
    assert "diff --name-only" in phase2_text, \
        "diff --name-only not found in Phase 2 provenance filter section"

    # Locate the provenance filter step 1 within Phase 2 to narrow the ..HEAD absence check
    provenance_filter_idx = phase2_text.find("**Provenance filter**")
    assert provenance_filter_idx >= 0, \
        "Provenance filter section not found in Phase 2 of agents/changelog-analyst.md"
    # Take only up to the next phase heading to avoid false matches in later sections
    next_phase_idx = phase2_text.find("### Phase 3", provenance_filter_idx)
    provenance_filter_section = phase2_text[provenance_filter_idx:next_phase_idx] \
        if next_phase_idx >= 0 else phase2_text[provenance_filter_idx:]

    # The ..HEAD form must NOT appear as an actual git command in the provenance filter.
    # It MAY appear in an explanatory "is WRONG" note — that is the correct documentation.
    # Check for ..HEAD or ...HEAD used as an actual git range in any diff/log command,
    # in any argument order (--name-only may come before or after the range).
    import re
    for line in provenance_filter_section.splitlines():
        has_head_range = bool(re.search(r"\.\.\S*HEAD", line))
        has_diff_cmd = bool(re.search(r"\bgit\b.*\bdiff\b|\bdiff\b.*--name-only", line))
        if has_head_range and has_diff_cmd:
            # Allowed only if the line is clearly an explanatory negation (contains WRONG, must NOT, etc.)
            is_negation_explanation = bool(re.search(
                r"(?i)(wrong|must\s+not|do\s+not\s+use|incorrect|do\s+not)", line
            ))
            assert is_negation_explanation, \
                (f"Found ..HEAD in what appears to be an actual git diff command in Phase 2 "
                 f"provenance filter (not an explanatory warning): {line!r}. "
                 "Phase 2 runs before commit so ..HEAD returns empty and would falsely "
                 "flag all legitimate working-tree changes as provenance_anomaly.")

    # Also verify the text explicitly warns that ..HEAD must NOT be used:
    # require ..HEAD near a negation word within 150 characters
    has_head_warning = bool(re.search(
        r"(?is)(\.\.HEAD.{0,150}(wrong|must\s+not|do\s+not|incorrect)|"
        r"(?:wrong|must\s+not|do\s+not|incorrect).{0,150}\.\.HEAD)",
        provenance_filter_section
    ))
    assert has_head_warning, \
        ("Phase 2 provenance filter should explicitly warn that ..HEAD must not be used "
         "(require '..HEAD' within 150 chars of a negation word like WRONG, 'must NOT', "
         "'do not', or 'incorrect'); no such warning found in the section")
